mapper.sql:
1=1

/*대상 검색*/

    AND lm.HDQR_BOB_DCD = #{searchTarget}


/*구분 검색*/

    AND lm.LEARNING_TYPE = #{searchLearningType}


/*상태 검색*/

    AND dh.RESULT = #{searchResultStatusType}


/*검색어 검색*/

    AND (
        lm.LEARN_NAME LIKE CONCAT('%', #{searchKeyword}, '%')
        OR COALESCE(hm.MEM_NAME, dh.EXEC_ID) LIKE CONCAT('%', #{searchKeyword}, '%')
    )


/*일자 검색*/

    AND dh.EXEC_DT BETWEEN CONCAT(REPLACE(#{searchStartDate}, '-', ''), ' 00:00:00') AND
    CONCAT(REPLACE(#{searchEndDate}, '-', ''), ' 23:59:59')
